mapper.select:
SELECT * FROM oa_approval_record
WHERE business_type = #{businessType} AND business_id = #{businessId}
ORDER BY create_time DESC

SELECT ar.id, ar.record_no, ar.business_type, CASE ar.business_type WHEN 'LEAVE' THEN '请假' WHEN 'EXPENSE' THEN '报销' WHEN 'PURCHASE' THEN '采购' WHEN 'SALARY' THEN '工资' WHEN 'STAMP' THEN '用印' WHEN 'OVERTIME' THEN '加班' WHEN 'BUSINESS_TRIP' THEN '出差' WHEN 'REPAIR_CARD' THEN '补卡' WHEN 'OUTING' THEN '外出' ELSE ar.business_type END AS business_type_name, ar.business_id, ar.user_id, ar.user_name, ar.dept_id, ar.dept_name, ar.title, ar.amount, ar.start_date, ar.end_date, ar.status, CASE ar.status WHEN 'PENDING' THEN '审批中' WHEN 'APPROVED' THEN '已通过' WHEN 'REJECTED' THEN '已拒绝' WHEN 'CANCELLED' THEN '已撤回' ELSE ar.status END AS status_name, ar.current_node, ar.total_nodes, ar.completed_nodes, CONCAT(ar.completed_nodes, '/', ar.total_nodes) AS progress, ar.create_time, DATE_FORMAT(ar.create_time, '%Y-%m-%d %H:%i') AS create_time_str FROM oa_approval_record ar
AND ar.user_id = #{userId} AND ar.business_type = #{businessType} AND ar.status = #{status} AND ar.create_time >= #{startDate} AND ar.create_time <= #{endDate}
ORDER BY ar.create_time DESC

SELECT ar.id, ar.record_no, ar.business_type, CASE ar.business_type WHEN 'LEAVE' THEN '请假' WHEN 'EXPENSE' THEN '报销' WHEN 'PURCHASE' THEN '采购' WHEN 'SALARY' THEN '工资' WHEN 'STAMP' THEN '用印' WHEN 'OVERTIME' THEN '加班' WHEN 'BUSINESS_TRIP' THEN '出差' WHEN 'REPAIR_CARD' THEN '补卡' WHEN 'OUTING' THEN '外出' ELSE ar.business_type END AS business_type_name, ar.business_id, ar.user_id, ar.user_name, ar.dept_id, ar.dept_name, ar.title, ar.amount, ar.start_date, ar.end_date, ar.status, CASE ar.status WHEN 'PENDING' THEN '审批中' WHEN 'APPROVED' THEN '已通过' WHEN 'REJECTED' THEN '已拒绝' WHEN 'CANCELLED' THEN '已撤回' ELSE ar.status END AS status_name, ar.current_node, ar.total_nodes, ar.completed_nodes, CONCAT(ar.completed_nodes, '/', ar.total_nodes) AS progress, ar.create_time, DATE_FORMAT(ar.create_time, '%Y-%m-%d %H:%i') AS create_time_str FROM oa_approval_record ar
AND ar.user_id = #{userId} AND ar.dept_id = #{deptId} AND ar.business_type = #{businessType} AND ar.status = #{status} AND ar.create_time >= #{startDate} AND ar.create_time <= #{endDate}
ORDER BY ar.create_time DESC
